<main class="container-fluid admin-shell"><div class="row g-4"><aside class="col-lg-2"><?php require __DIR__.'/../includes/sidebar.php'; ?></aside><section class="col-lg-10"><div class="d-flex justify-content-between align-items-center mb-4"><h1 class="section-title mb-0">Manage Products</h1><a class="btn btn-primary" href="<?= url('admin/add_product.php') ?>"><i class="bi bi-plus"></i>Add Product</a></div><form class="card form-card p-3 mb-4 no-loader" method="get"><div class="row g-3"><div class="col-md-4"><input name="q" class="form-control" placeholder="Search products" value="<?= e($filters['q']) ?>"></div><div class="col-md-3"><select name="category_id" class="form-select"><option value="">All categories</option><?php foreach($categories as $cat): ?><option value="<?= (int)$cat['id'] ?>" <?= (int)$filters['category_id']===(int)$cat['id']?'selected':'' ?>><?= e($cat['category_name']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><select name="status" class="form-select"><option value="">All status</option><option value="active" <?= $filters['status']==='active'?'selected':'' ?>>Active</option><option value="inactive" <?= $filters['status']==='inactive'?'selected':'' ?>>Inactive</option></select></div><div class="col-md-2"><button class="btn btn-primary w-100">Filter</button></div></div></form><div class="card table-card"><div class="table-responsive"><table class="table align-middle mb-0"><thead class="table-light"><tr><th>Image</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach($products as $p): ?><tr><td><img class="cart-thumb" src="<?= e(product_image_url($p['image'])) ?>"></td><td><?= e($p['product_name']) ?></td><td><?= e($p['category_name']) ?></td><td><?= money((float)($p['discount_price'] ?? $p['price'])) ?></td><td><span class="badge <?= (int)$p['stock_quantity'] <= (int)setting('low_stock_threshold','5') ? 'bg-danger' : 'bg-success' ?>"><?= (int)$p['stock_quantity'] ?></span></td><td><span class="badge bg-<?= $p['status']==='active'?'success':'secondary' ?>"><?= e($p['status']) ?></span></td><td><a class="btn btn-sm btn-outline-primary" href="<?= url('admin/edit_product.php?id='.(int)$p['id']) ?>">Edit</a><form method="post" class="d-inline confirm-form no-loader"><?= csrf_input() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= (int)$p['id'] ?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach; if(!$products): ?><tr><td colspan="7" class="text-center text-muted py-4">No products found.</td></tr><?php endif; ?></tbody></table></div></div><?php if($pages>1): ?><nav class="mt-4"><ul class="pagination justify-content-center"><?php for($i=1;$i<=$pages;$i++): $q=$_GET; $q['page']=$i; ?><li class="page-item <?= $i===$page?'active':'' ?>"><a class="page-link" href="?<?= http_build_query($q) ?>"><?= $i ?></a></li><?php endfor; ?></ul></nav><?php endif; ?></section></div></main>
